# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
from typing import Dict, List, Set
from dataclasses import dataclass
from datetime import datetime

@dataclass
class Item:
    id: str
    name: str
    type: str
    value: int
    owner_id: str

@dataclass
class Player:
    id: str
    username: str
    inventory: Dict[str, int]
    websocket: websockets.WebSocketServerProtocol

class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.trade_requests: Dict[str, Dict] = {}
        self.lock = asyncio.Lock()
        self.item_counter = 0

    async def register_player(self, websocket, username):
        player_id = str(uuid.uuid4())
        player = Player(player_id, username, {}, websocket)
        self.players[player_id] = player
        await self.send_message(websocket, {
            "type": "player_registered",
            "player_id": player_id
        })
        return player_id

    async def unregister_player(self, player_id):
        if player_id in self.players:
            del self.players[player_id]

    async def send_message(self, websocket, message):
        try:
            await websocket.send(json.dumps(message))
        except:
            pass

    async def handle_message(self, websocket, message_str):
        try:
            message = json.loads(message_str)
            message_type = message.get("type")
            
            if message_type == "register":
                player_id = await self.register_player(websocket, message.get("username"))
                await self.send_message(websocket, {
                    "type": "registration_success",
                    "player_id": player_id
                })
                
            elif message_type == "create_item":
                await self.create_item(message.get("player_id"), message.get("item_data"))
                
            elif message_type == "trade_request":
                await self.handle_trade_request(message.get("from_player_id"), 
                                               message.get("to_player_id"), 
                                               message.get("item_id"), 
                                               message.get("quantity"))
                
            elif message_type == "trade_response":
                await self.handle_trade_response(message.get("player_id"), 
                                                message.get("trade_id"), 
                                                message.get("accepted"))
                
            elif message_type == "get_inventory":
                await self.send_inventory(message.get("player_id"))
                
        except Exception as e:
            print(f"Error handling message: {e}")

    async def create_item(self, player_id, item_data):
        if player_id not in self.players:
            return
            
        item_id = f"item_{self.item_counter}"
        self.item_counter += 1
        
        item = Item(
            id=item_id,
            name=item_data["name"],
            type=item_data["type"],
            value=item_data["value"],
            owner_id=player_id
        )
        
        self.items[item_id] = item
        
        # Add to player's inventory
        if item_id not in self.players[player_id].inventory:
            self.players[player_id].inventory[item_id] = 0
        self.players[player_id].inventory[item_id] += 1
        
        await self.broadcast_item_update(item_id, item)

    async def handle_trade_request(self, from_player_id, to_player_id, item_id, quantity):
        if from_player_id not in self.players or to_player_id not in self.players:
            return
            
        if item_id not in self.items:
            return
            
        if self.items[item_id].owner_id != from_player_id:
            return
            
        trade_id = str(uuid.uuid4())
        
        self.trade_requests[trade_id] = {
            "from_player_id": from_player_id,
            "to_player_id": to_player_id,
            "item_id": item_id,
            "quantity": quantity,
            "timestamp": datetime.now().isoformat()
        }
        
        # Notify target player
        target_player = self.players[to_player_id]
        await self.send_message(target_player.websocket, {
            "type": "trade_offer",
            "trade_id": trade_id,
            "from_player_id": from_player_id,
            "item_id": item_id,
            "quantity": quantity
        })

    async def handle_trade_response(self, player_id, trade_id, accepted):
        if trade_id not in self.trade_requests:
            return
            
        trade = self.trade_requests[trade_id]
        
        if trade["to_player_id"] != player_id:
            return
            
        if accepted:
            await self.execute_trade(trade)
            
        del self.trade_requests[trade_id]
        
        # Notify both players
        from_player = self.players[trade["from_player_id"]]
        to_player = self.players[trade["to_player_id"]]
        
        await self.send_message(from_player.websocket, {
            "type": "trade_result",
            "trade_id": trade_id,
            "accepted": accepted
        })
        
        await self.send_message(to_player.websocket, {
            "type": "trade_result",
            "trade_id": trade_id,
            "accepted": accepted
        })

    async def execute_trade(self, trade):
        from_player_id = trade["from_player_id"]
        to_player_id = trade["to_player_id"]
        item_id = trade["item_id"]
        quantity = trade["quantity"]
        
        async with self.lock:
            # Check if item exists and has enough quantity
            if item_id not in self.items:
                return
                
            item = self.items[item_id]
            
            # Remove from original owner
            if from_player_id in self.players and item_id in self.players[from_player_id].inventory:
                self.players[from_player_id].inventory[item_id] -= quantity
                if self.players[from_player_id].inventory[item_id] <= 0:
                    del self.players[from_player_id].inventory[item_id]
            
            # Add to new owner
            if to_player_id in self.players:
                if item_id not in self.players[to_player_id].inventory:
                    self.players[to_player_id].inventory[item_id] = 0
                self.players[to_player_id].inventory[item_id] += quantity
            
            # Update item ownership
            item.owner_id = to_player_id
            
            # Broadcast update
            await self.broadcast_item_update(item_id, item)

    async def send_inventory(self, player_id):
        if player_id not in self.players:
            return
            
        player = self.players[player_id]
        inventory_data = []
        
        for item_id, quantity in player.inventory.items():
            if item_id in self.items:
                item = self.items[item_id]
                inventory_data.append({
                    "item_id": item_id,
                    "name": item.name,
                    "type": item.type,
                    "value": item.value,
                    "quantity": quantity
                })
        
        await self.send_message(player.websocket, {
            "type": "inventory_update",
            "inventory": inventory_data
        })

    async def broadcast_item_update(self, item_id, item):
        message = {
            "type": "item_update",
            "item_id": item_id,
            "name": item.name,
            "type": item.type,
            "value": item.value,
            "owner_id": item.owner_id
        }
        
        # Send to all players who might be interested
        for player in self.players.values():
            await self.send_message(player.websocket, message)

    async def handle_client(self, websocket, path):
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        except websockets.exceptions.ConnectionClosed:
            pass
        except Exception as e:
            print(f"Client handling error: {e}")
        finally:
            # Clean up on disconnect
            for player_id, player in list(self.players.items()):
                if player.websocket == websocket:
                    await self.unregister_player(player_id)
                    break

# Start the server
async def main():
    server = GameServer()
    start_server = websockets.serve(server.handle_client, "localhost", 8765)
    await start_server
    print("Game server started on ws://localhost:8765")
    await asyncio.Future()  # Run forever

if __name__ == "__main__":
    asyncio.run(main())